INSERT INTO "aibrewgenius"."ai_generated_recipes_v2" ("id", "user_profile_id", "basis_bier", "bier_typ", "stammwuerze_sg", "restextrakt_sg", "alkoholgehalt", "notizen", "generated_image", "yeast_name", "yeast_type", "yeast_amount", "yeast_procurement_needed", "water_ca", "water_mg", "water_na", "water_cl", "water_so4", "water_hco3", "water_salt_timing", "mash_water_l", "mash_in_temp_c", "lauter_sparge_water_l", "lauter_target_ph", "boil_pre_vol_l", "boil_duration_min", "fermentation_pitch_temp_c", "packaging_type", "packaging_co2_target", "packaging_keg_pressure", "packaging_keg_temp", "packaging_bottle_sugar", "packaging_bottle_temp", "packaging_storage_temp", "packaging_storage_weeks", "packaging_maturation_note", "packaging_serving_gas", "packaging_carb_days", "can_pressurize", "fermentation_pressure_note", "bjcp_stil", "ibu", "created_at", "updated_at", "malts", "hops", "specials", "finings", "mash_steps", "fermentation_steps") VALUES
	('9166ad6a-f8a3-47fe-9f44-7331aca4d4ae', 'self_hosted_profile', 'Märzen / Festbier nach klassischem Münchner Vorbild', 'Märzen (untergärig, bernsteinfarben, malzbetont)', 1.054, 1.012, 5.5, '{"Volumen- und Wasserberechnung (Ziel: 23.0 L fertiges Bier im Gebinde):
- Ziel im Gebinde: 23.0 L
- Gärverlust (Hefe/Trub im Fermenter): 2.0 L
=> Benötigte Menge im Gärbehälter (Batch Size kalt): 25.0 L
- Kesselschwund nach Kochung (Trub): 4.0 L
=> Benötigte heiße Würze nach Kochung (Post-Boil heiß): 29.0 L
- Kühl-Schrumpfung 4 %: 29.0 L heiß ≈ 27.84 L kalt. Davon 2.0 L Gärverlust => ~25.84 L potentiell abfüllbar. Leichte Sicherheitsreserve durch etwas höheren Kesselverlust und Prozessverluste führt realistisch zu 25.0 L im Fermenter und 23.0 L im Gebinde.
- Verdunstung: 2.5 % pro Stunde, Kochzeit 70 min ≈ 2.9 % Gesamtverlust.
=> Pfannevoll (Pre-Boil) = 29.0 L / (1 - 0.029) ≈ 29.9 L, auf 30.0 L gerundet.

Maische- und Wasserbilanz:
- Gesamtmalz: 7.05 kg
- Malz-Absorption: 0.9 L/kg * 7.05 kg ≈ 6.35 L im Treber gebunden.
- Hauptguss: 22.0 L => Nach Läutern verbleiben ca. 22.0 - 6.35 ≈ 15.65 L Würze.
- Benötigte Pfannevollwürze: 30.0 L => erforderlicher Nachguss ≈ 30.0 - 15.65 = 14.35 L.
- Geplanter Nachguss: 19.0 L gibt ca. 34.65 L Gesamtwürze theoretisch; durch Läuterstopp und Trubverluste vor dem Kessel erreicht man in der Praxis die Ziel-Pfannevollmenge von 30.0 L.

Stilabgleich:
- Ziel Stammwürze: 1.054 (typischer Bereich für klassisches Märzen/Festbier).
- Erwartete Endvergärung mit Wyeast 2206: ca. 76–78 %, hier auf 77 % angesetzt => Restextrakt ca. 1.012, Alkohol ~5.5 % vol.
- Hopfung mit ca. 80 g klassischer Edelhopfen (Hallertauer Mittelfrüh, Tettnanger) ergibt ~22–26 IBU je nach tatsächlichem Alpha-Wert und Systemausbeute, passend zum malzbetonten, moderat gehopften Märzenstil.

Karbonisierung:
- Zielvolumen CO2: ca. 2.3–2.4 Vol., das entspricht etwa 4.5–5.0 g/L CO2; hier 5.0 g/L als leicht spritzige, aber noch stilechte Karbonisierung.
- Keg: Bei 14 °C sind ca. 1.2 bar Überdruck ausreichend, um etwa 2.3–2.4 Vol. CO2 zu erreichen (leichte Systemtoleranz eingerechnet).
- Flasche: 6 g Zucker/L (Haushaltszucker) ergeben ungefähr 2.3–2.4 Vol. CO2, unter Annahme, dass das Bier vor Abfüllung noch ca. 0.8–1.0 Vol. Rest-CO2 enthält.

Gärdruck-Strategie:
- Leichte Druckvergärung (0.3–0.5 bar) bei Lagerbieren führt zu sehr sauberem Profil und reduziert Ester, ohne die Hefe zu stark zu belasten.
- In der Lagerphase 1.0 bar, um CO2 im Bier zu halten und Oxidation zu minimieren.

Anpassungen:
- Falls die Sudhausausbeute deutlich von ca. 70–75 % abweicht, Malzmenge entsprechend anpassen, um die Ziel-Stammwürze 1.054 zu treffen.
- Hopfengaben ggf. nach real gemessenen Alpha-Säuren korrigieren, um ~24 IBU zu erreichen.
- Wasserprofil an lokales Wasser anpassen; HCO3 ggf. mit Milchsäure senken, wenn das Ausgangswasser sehr hart ist."}', '', 'Wyeast 2206 Bavarian Lager', 'Untergaerig', '2 Päckchen (oder 1 Päckchen mit entsprechend großem Starter ~2 L)', false, 60, 8, 10, 70, 60, 80, 'Beides', 22, 52, 19, '5.4 - 5.6', 30, 70, 9, 'Beides', 5, 1.2, 14, 6, 23, 4, 4, 'Märzen profitiert von längerer Kaltlagerung. Nach der Karbonisierung im Keg noch mindestens 3–4 Wochen bei 2–4 °C lagern. Flaschen nach der Nachgärung (ca. 10–14 Tage bei 20–23 °C) ebenfalls kühl stellen und weitere 3–4 Wochen reifen lassen.', 'CO2', 10, false, NULL, NULL, NULL, '2026-01-04 19:50:55.973223+00', '2026-01-04 19:50:55.973223+00', '[{"name": "Pilsner Malz", "amount_kg": 3, "crush_gap_mm": 1.2}, {"name": "Münchner Malz hell", "amount_kg": 3, "crush_gap_mm": 1.2}, {"name": "Wiener Malz", "amount_kg": 0.8, "crush_gap_mm": 1.2}, {"name": "Caramünch I", "amount_kg": 0.25, "crush_gap_mm": 1.2}]', '[{"name": "Hallertauer Mittelfrüh", "amount_g": 40, "time_min": 60, "use_type": "Kochen", "alpha_acid": 4}, {"name": "Hallertauer Mittelfrüh", "amount_g": 20, "time_min": 20, "use_type": "Kochen", "alpha_acid": 4}, {"name": "Tettnanger", "amount_g": 20, "time_min": 10, "use_type": "Whirlpool", "alpha_acid": 4}]', '[{"name": "", "unit": "", "amount": "", "detail": ""}]', '[{"name": "Whirlfloc", "phase": "Kochen (letzte 10 Minuten)", "amount": "1/2 Tablette", "detail": "Direkt in die kochende Würze bei noch 10 Minuten Kochzeit zugeben.", "purpose": "Heißtrub-Flockung, klarere Würze", "procurement_needed": false}, {"name": "Biersol", "phase": "Nach Hauptgärung, vor Kaltlagerung", "amount": "Nach Herstellerangabe (typ. 1 ml pro L Jungbier)", "detail": "In gut durchmischtes Jungbier einrühren, dann kalt lagern.", "purpose": "Feinklärung, schnellere Brillanz", "procurement_needed": false}]', '[{"stage": "Einmaischen / Eiweißrast (optional, bei gut modifiziertem Malz kann verkürzt werden)", "temp_c": 52, "duration_min": 10}, {"stage": "Maltoserast", "temp_c": 63, "duration_min": 40}, {"stage": "Verzuckerungsrast", "temp_c": 72, "duration_min": 25}, {"stage": "Abmaischen", "temp_c": 78, "duration_min": 10}]', '[{"days": 2, "note": "Gut belüften/oxygenieren (8–10 mg/L O2), um eine gesunde Lagerhefe-Gärung zu gewährleisten.", "phase": "Anstellen & Anlauf der Gärung", "temp_c": 9, "pressure_bar": 0.3, "pressure_note": "Leichter Druck reduziert Gärnebenprodukte (v.a. Ester) ohne die Hefeaktivität zu stark zu hemmen; bei Lagerbieren ist eine saubere, neutrale Aromatik gewünscht."}, {"days": 7, "note": "Gärverlauf beobachten; wenn ca. 70–75 % des scheinbaren Endvergärungsgrades erreicht sind, zur Diacetylrast übergehen.", "phase": "Hauptgärung", "temp_c": 10, "pressure_bar": 0.5, "pressure_note": "Moderater Druck hält Gäraromen sauber und reduziert CO2-Verluste, ohne die Vergärung zu bremsen."}, {"days": 2, "note": "Temperatur langsam (1–2 °C pro Tag) anheben, nicht schockartig.", "phase": "Diacetylrast", "temp_c": 14, "pressure_bar": 0.5, "pressure_note": "Gleicher moderater Druck; Temperaturerhöhung fördert den Abbau von Diacetyl und anderen Gärnebenprodukten."}, {"days": 2, "note": "Schrittweise Absenkung der Temperatur (max. 2–3 °C pro Tag), um die Hefe nicht zu stressen.", "phase": "Abkühlen auf Lager-Temperatur", "temp_c": 5, "pressure_bar": 0.8, "pressure_note": "Etwas höherer Druck verhindert übermäßige CO2-Entbindung beim Abkühlen und schützt vor Sauerstoffeintrag."}, {"days": 28, "note": "Hier kann optional Biersol zugegeben werden, um die Klärung zu beschleunigen. Möglichst temperaturstabil lagern.", "phase": "Lagerung / Reifung (Kaltlagerung)", "temp_c": 2, "pressure_bar": 1, "pressure_note": "Leichter Überdruck hält CO2 im Bier gelöst, verbessert die Lagerstabilität und unterstützt die Klärung ohne die Hefeaktivität noch relevant zu beeinflussen."}]'),
	('2699b92d-654d-4d4d-b011-655f66d9e499', 'self_hosted_profile', 'Starkbier mit Gefrierkonzentration (Eisbock) auf Basis eines dunklen Bocks', 'Dunkler Eisbock (untergärig, auf Basis Dunkler Bock / Doppelbock)', 1.092, 1.026, 10, '{"Volumen- und Wasserrechnung (für 23,0 L fertiges Bier im Gebinde): Ziel: 23,0 L im Gebinde. Gärverlust: 2,0 L → benötigt im Fermenter nach Eisbock-Prozess: 25,0 L. Eisbock-Konzentrierung: ca. 25–30 % Volumenverlust durch Ausfrieren von Wasser. Geplant: ca. 34 L Jungbier vor dem Einfrieren → nach Entfernen von ~9–11 L Eis bleiben etwa 23–25 L konzentrierter Eisbock. Daher wird die Würze bewusst etwas überproduziert. Kesselverlust: 4,0 L. Ziel kalte Anstellwürze im Fermenter vor Eisbock: ca. 34 L. Zuzüglich 4 % Kühl-Schrumpfung: heißes Volumen am Kochende: 34 L / 0,96 ≈ 35,4 L. Verdunstung 2,5 %/h, Kochzeit 1,5 h → ca. 3,75 % Gesamtverlust. Pfannevoll (Pre-Boil) = 35,4 L / 0,9625 ≈ 36,8 L. Malzgesamtmenge: 7,8 kg. Malzabsorptionsverlust: 7,8 kg × 0,9 L/kg ≈ 7,0 L. Gesamt-Brauwasser = Pfannevoll (36,8 L) + Malzabsorption (7,0 L) ≈ 43,8 L. Aufgeteilt in Hauptguss ca. 24 L und Nachguss ca. 13 L (zusammen 37 L), zusätzlich ca. 6–7 L Wasseranteil aus Malzfeuchte und Messungenauigkeiten; diese Aufteilung ist für den Brewtools B40 praxisgerecht. Ggf. beim Läutern die Nachgussmenge feinjustieren, um Pfannevoll von ca. 36,8 L zu treffen.","Stilhinweis: Eisbock ist extrem malzbetont, mit intensiven Karamell-, Brot- und dunklen Fruchtnoten, sehr hohem Alkoholgehalt und niedrig bis moderat wahrnehmbarer Bittere. Die Hopfenbittere von ca. 25–30 IBU in der Ausgangswürze erscheint im fertigen Eisbock durch die Konzentration etwas höher, bleibt aber im Verhältnis zur enormen Malzsüße ausgewogen.","Gefrierkonzentration: Hygiene und Sauerstoffeintrag sind kritisch. Möglichst unter CO2-Atmosphäre umfüllen, Gefäß beim Einfrieren abdecken. Das Eis sollte milchig-weiß sein; klare, bernsteinfarbene Eisanteile enthalten viel Extrakt und sollten nicht entfernt werden. Lieber in mehreren Schritten arbeiten: Teilweise auftauen lassen, konzentrierte Flüssigphase abziehen, bis das Zielvolumen im Lagergefäß erreicht ist.","Hefe-Management: Bei dieser hohen Stammwürze ist ein gesunder, großer Starter entscheidend. Ein 2,5–3 L Starter aus einem Päckchen Wyeast 2206 (mit Belüftung/Rührer) ist empfehlenswert, oder 2 frische Päckchen direkt anstellen. Bei sehr frischer Hefe kann auch ein gestufter Starter gefahren werden.","Karbonisierung: Für einen Eisbock ist eine moderate Karbonisierung von etwa 1,9–2,1 Volumen CO2 (≈ 4,0–4,4 g/L) stiltypisch. Zu hohe Karbonisierung wirkt spritzig und stört das cremige Mundgefühl. Flaschen nach Zuckerzugabe 10–14 Tage bei 20–23 °C karbonisieren lassen, danach kühl stellen.","IBU-Abschätzung: Bei ca. 36,8 L Pfannevoll und 90 min Kochzeit ergeben 30 g Magnum (12 % Alpha, 60 min) und 25 g Mittelfrüh (4 %, 20 min) in gängigen Modellen etwa 28–30 IBU in der Ausgangswürze. Durch die spätere Gefrierkonzentration steigt die effektive Bittere im fertigen Eisbock rechnerisch auf etwa 35–40 IBU, was im Verhältnis zur massiven Restsüße harmonisch bleibt.","Eisbock-spezifisch: Nach der Gefrierkonzentration wird das Bier deutlich dichter und alkoholreicher. Die angegebene Enddichte von etwa 1.026 bezieht sich auf die konzentrierte Bierphase. Sensorisch ist eine deutliche, aber nicht scharfe Alkoholwärme gewünscht; die lange Lagerung hilft, Kanten abzubauen."}', '', 'Wyeast 2206 Bavarian Lager', 'Untergaerig', '2 Pkg (oder 1 großer Starter ~2,5–3,0 L)', false, 60, 10, 15, 70, 60, 80, 'Beides', 24, 63, 13, '5.3 - 5.6', 30.3, 90, 8, 'Beides', 4.2, 1.5, 14, 5, 23, 14, 8, 'Eisbock profitiert stark von langer Reifung. Nach Karbonisierung mindestens 6–8 Wochen bei 10–14 °C lagern, danach gerne weiter bei Keller- oder Kühlschranktemperatur (bis zu 1–2 Jahre). Für Keg-Ausschank bei 10–12 °C servieren, CO2-Druck bei Ausschank ca. 1,0–1,2 bar halten.', 'CO2', 10, false, NULL, NULL, NULL, '2026-01-04 21:43:55.464166+00', '2026-01-04 21:43:55.464166+00', '[{"name": "Münchner Malz hell", "amount_kg": 5, "crush_gap_mm": 1.3}, {"name": "Pilsner Malz", "amount_kg": 1.5, "crush_gap_mm": 1.3}, {"name": "Wiener Malz", "amount_kg": 0.8, "crush_gap_mm": 1.3}, {"name": "Caramünch II", "amount_kg": 0.35, "crush_gap_mm": 1.2}, {"name": "Carafa Spezial II (entbittert)", "amount_kg": 0.15, "crush_gap_mm": 1.2}]', '[{"name": "Hallertauer Magnum", "amount_g": 30, "time_min": 60, "use_type": "Kochen", "alpha_acid": 12}, {"name": "Hallertauer Mittelfrüh", "amount_g": 25, "time_min": 20, "use_type": "Kochen", "alpha_acid": 4}]', '[{"name": "Hefe-Nahrung (optional)", "unit": "g", "amount": "3", "detail": "Letzten 10 Minuten des Kochens zugeben"}]', '[{"name": "Whirlfloc", "phase": "Kochen", "amount": "1/2 Tablette", "detail": "15 Minuten vor Kochende zugeben", "purpose": "Eiweißfällung, klarere Würze", "procurement_needed": false}, {"name": "Biersol", "phase": "Nach Hauptgärung, vor Kaltlagerung", "amount": "Nach Herstellerangabe (typ. 1 ml/L)", "detail": "In die Jungbieroberfläche einrühren und 5–7 Tage kalt stehen lassen", "purpose": "Zusätzliche Klärung des Starkbieres", "procurement_needed": false}]', '[{"stage": "Maltoserast", "temp_c": 63, "duration_min": 45}, {"stage": "Verzuckerungsrast", "temp_c": 70, "duration_min": 25}, {"stage": "Abmaischen", "temp_c": 76, "duration_min": 10}]', '[{"days": 3, "note": "Gut belüften (mind. 2x O2-Gabe oder intensive Luftbelüftung), da hohe Stammwürze die Hefe stark belastet.", "phase": "Hauptgärung (Anstellung und Anlauf)", "temp_c": 8, "pressure_bar": 0.3, "pressure_note": "Leichter Druck reduziert früh entstehende Gärungsester und hält CO2 im Bier, ohne die Hefeaktivität in der kritischen Anlaufphase zu stark zu hemmen."}, {"days": 7, "note": "Gärverlauf beobachten; bei ~50–60% scheinbarem Vergärungsgrad leicht auf 10 °C anheben.", "phase": "Hauptgärung (aktive Phase)", "temp_c": 9, "pressure_bar": 0.7, "pressure_note": "Moderater Druck unterstützt ein sauberes untergäriges Profil, reduziert Gärungsnebenprodukte und erhält mehr CO2 für ein weicheres Mundgefühl."}, {"days": 2, "note": "Erst nach stabilem Restextrakt und sensorischer Probe (keine Butter-/Toffeenote) in die Kaltphase gehen.", "phase": "Diacetylrast", "temp_c": 12, "pressure_bar": 0.5, "pressure_note": "Leichter Druck reicht aus, um Oxidation und übermäßige CO2-Abgabe zu vermeiden, lässt der Hefe aber genügend Freiheit, Diacetyl und andere Gärungsnebenprodukte abzubauen."}, {"days": 3, "note": "Jetzt optional Biersol zugeben, bevor die Temperatur erreicht ist, und gut einmischen.", "phase": "Cold Crash / Vorklärung", "temp_c": 2, "pressure_bar": 0.3, "pressure_note": "Niedriger Überdruck verhindert Lufteintrag beim Abkühlen und hilft CO2 im Bier zu halten, ohne übermäßige Karbonisierung zu verursachen."}, {"days": 7, "note": "Bier weitgehend klären lassen, bevor es in ein Gefäß zum Einfrieren umgeschlaucht wird.", "phase": "Lagerung vor dem Einfrieren", "temp_c": 2, "pressure_bar": 0.3, "pressure_note": "Konstanter leichter Druck schützt vor Sauerstoffeintrag und hält das Bier leicht gesättigt, was der Reifung eines Starkbieres zugutekommt."}, {"days": 2, "note": "Bier in ein geeignetes, lebensmittelechtes Gefäß umfüllen. Bei ca. -2 bis -3 °C einfrieren, bis etwa 25–30% Volumen als Eis ausfallen. Flüssigphase vorsichtig abziehen, Zielvolumen ca. 23 L im Gär-/Lagergefäß.", "phase": "Eisbock-Phase (Gefrierkonzentration, externes Gefäß)", "temp_c": -2.5, "pressure_bar": 0, "pressure_note": "Gefrierkonzentration erfolgt üblicherweise in einem nicht druckfesten Gefäß; das Bier ist bereits vergoren und darf drucklos konzentriert werden."}, {"days": 21, "note": "Nach dem Einfrieren ist das Bier alkoholreicher und profitiert stark von längerer kalter Lagerung zur Harmonisierung.", "phase": "Nachlagerung / Reifung nach dem Einfrieren", "temp_c": 2, "pressure_bar": 0.3, "pressure_note": "Leichter Druck verhindert Sauerstoffeintrag und erhält CO2; wichtig für Stabilität und Rundung des sehr starken Bieres."}]');


