-7f820fa1", "ibu": 39.9, "use": "Boil", "name": "East Kent Goldings (EKG)", "time": 60, "type": "Pellet", "alpha": 4.7, "usage": "Both", "amount": 69, "origin": "United Kingdom", "_editFlag": true, "actualTime": null}], "mash": {"_id": "default", "name": "Guiness BYO Mash Profile", "steps": [{"name": "Mash", "type": "Temperature", "rampTime": null, "stepTemp": 65, "stepTime": 90, "displayStepTemp": 65}, {"name": "Mashout", "type": "Temperature", "rampTime": null, "stepTemp": 74, "stepTime": 10, "displayStepTemp": 74}]}, "name": "Guiness Clone", "path": "/", "tags": null, "type": "All Grain", "_init": true, "_type": "recipe", "color": 36.6, "miscs": [{"_id": "default-2302b0", "use": "Mash", "name": "Baking Soda (NaHCO3)", "time": null, "type": "Water Agent", "unit": "g", "amount": 3, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-3b1827", "use": "Mash", "name": "Calcium Chloride (CaCl2)", "time": null, "type": "Water Agent", "unit": "g", "amount": 1.7, "timeIsDays": false, "concentration": null, "waterAdjustment": true}, {"_id": "default-bk9j78", "use": "Mash", "name": "Canning Salt (NaCl)", "time": null, "type": "Water Agent", "unit": "g", "amount": 0.4, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-4e9d62", "use": "Mash", "name": "Epsom Salt (MgSO4)", "time": null, "type": "Water Agent", "unit": "g", "amount": 2.2, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-1f88df", "use": "Mash", "name": "Gypsum (CaSO4)", "time": null, "type": "Water Agent", "unit": "g", "amount": 1.5, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-07adb1", "use": "Mash", "name": "Lactic Acid", "time": null, "type": "Water Agent", "unit": "ml", "amount": 1, "timeIsDays": false, "concentration": 88, "waterAdjustment": true}, {"_id": "default-3b1827", "use": "Sparge", "name": "Calcium Chloride (CaCl2)", "time": null, "type": "Water Agent", "unit": "g", "amount": 1.89, "timeIsDays": false, "concentration": null, "waterAdjustment": true}, {"_id": "default-bk9j78", "use": "Sparge", "name": "Canning Salt (NaCl)", "time": null, "type": "Water Agent", "unit": "g", "amount": 0.44, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-4e9d62", "use": "Sparge", "name": "Epsom Salt (MgSO4)", "time": null, "type": "Water Agent", "unit": "g", "amount": 2.44, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-1f88df", "use": "Sparge", "name": "Gypsum (CaSO4)", "time": null, "type": "Water Agent", "unit": "g", "amount": 1.66, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-07adb1", "use": "Sparge", "name": "Lactic Acid", "time": null, "type": "Water Agent", "unit": "ml", "amount": 0.24, "timeIsDays": false, "concentration": 80, "waterAdjustment": true}, {"_id": "default-8mv12", "use": "Boil", "name": "Whirlfloc", "time": 15, "type": "Fining", "unit": "items", "amount": 1, "timeIsDays": false}], "notes": "https://web.archive.org/web/20130120122623/byo.com/stories/beer-styles/article/indices/11-beer-styles/1458-stout-hearted-in-ireland\n\n\nMashing\nMcGovern notes that unlike those in corn and rice, the starches in raw barley do not have to be gelatinized before mashing. So no cooking is required. The enzymatic action of pale malt is strong enough to convert the starch into the sugars required for fermentation. So you won’t find any cereal cookers at the Guinness plant.\n\nGuinness’ new brew house is laid out in the traditional, top to bottom design. Though the grains are not milled on the top floor, they are sent there by conveyor for storage in the huge grist bins. To mash a batch of Guinness, you’ll need 22 tons of grist (48,501 lb.) of around 65 percent pale malt, 25 percent raw barley, and 10 percent roast. Add that to 50 tons of water (13,233 gallons) in the mash tun, where huge, automatic paddles and knives rotate through the mash to keep it loose and well-mixed.\n\nThe water comes from Ireland’s Wicklow mountains. It’s relatively soft, but with the right blend of minerals for a successful mash. It’s the same water that Arthur Guinness used to make stout back in the 18th century.\n\nThe mash rests at 57° C (135° F) for 75 minutes, then it is stepped up to 67° C (152.6° F) and held for 45 minutes, then mashed out at 78° C (172° F).\n\nThe mash is fully converted in just over two hours, but the whole process takes about three. After mash-out it is automatically transferred to the kieve (pronounced “keev”).\n\n“Kieve is a term unique to Ireland,” McGovern says. “Most breweries call this vessel the lauter tun, where the mash is strained and rinsed over a false bottom to extract the sweet wort for fermentation.” The word is derived from the French word for copper, cuivre, pronounced “kweev.” McGovern says the Irish just like to be different.\n\n\nFor souring you can do multiple ways:\n1) Naturally sour part of the beer\n2) Add lactic acid at kegging time.\n3) Replace some the base malt with acid malt. \n\nI choose 2 as I can dose to my taste.\n", "style": {"_id": "default-47", "name": "Irish Stout", "type": "Stout", "fgMax": 1.011, "fgMin": 1.007, "ogMax": 1.044, "ogMin": 1.036, "abvMax": 4.5, "abvMin": 4, "ibuMax": 45, "ibuMin": 25, "rbrMax": 1.12, "rbrMin": 0.62, "buGuMax": 1.12, "buGuMin": 0.62, "carbMax": null, "carbMin": null, "category": "Irish Beer", "colorMax": 40, "colorMin": 25, "styleGuide": "BJCP 2015", "lovibondMax": 40, "lovibondMin": 25, "styleLetter": "B", "categoryNumber": "15", "carbonationStyle": "15B"}, "thumb": "data:image/jpeg;base64,", "water": {"mash": {"ph": 7.55, "_id": "BxaoyPTyb36ynD8b5nF6Ck46Np0eVQ", "_rev": "oRmnre0GUhZtLdfpvix0GA997BPQgO", "name": "Glattfelden", "type": "source", "anions": 9.094, "hidden": false, "sodium": 87.424, "calcium": 146.945, "cations": 14.104, "sulfate": 155.389, "_created": {"_seconds": 1711395249, "_nanoseconds": 482000000}, "_version": "2.20.3", "chloride": 104.651, "hardness": 515, "magnesium": 36.072, "soClRatio": 1.48, "_timestamp": {"_seconds": 1763053189, "_nan