atchHops": [], "boilSteps": [{"name": "", "time": 0}], "_timestamp": {"_seconds": 1757271847, "_nanoseconds": 613000000}, "batchMiscs": [], "measuredOg": 1.0444, "tasteNotes": "Jungbier probe:\nKein Co2 und ca 16 Grad kühl.\n\nMit dem Auge : Farbe ist ein sehr dunkles Rot bis Braun\n\nMit der Nase : Malz röst Aromen , leichte säure.\n\nIm Mund , guter säure Anteil , guter Malz röst anteil leicht nussig und caramel. Ein leichter metallischer Geschmack. Wie Kupfer mit Kühlwasser.\n\nAbgang Leicht , das Brechen des Wassers mit Milchsäure ist deutlich bemerkbar. Kein kratzen und läuft leicht runter. Wiederum guter Malzanteil spürbar.\n\nErstes mal Luft danach : Säure mit leichter süsse, metal aber angenehmes prickeln im Mund. Schmeckt ein bisschen wie übervergoren.\n\nVerbesserungspotential : Das Bier ist zu leicht . Die 20 Liter sind da wohl eher zuviel. 18,5 würden wohl reicher, dann wäre dass Bier wuchtiger. Es fehlt der Körper.\n\nDennoch als Irish Ale würde das wohl gut durchgehn , eher flach nicht aufdringlich und leicht.\n", "batchYeasts": [], "estimatedFg": 1.01, "estimatedOg": 1.044, "measuredAbv": 4.5, "tasteRating": 0, "bottlingDate": 1714916118525, "measurements": [], "_timestamp_ms": 1757271847613, "measuredOgSet": true, "batchHopsLocal": [], "boilStepsCount": 1, "estimatedColor": 2.7, "mashStepsCount": 0, "batchMiscsLocal": [], "bottlingDateSet": true, "carbonationTemp": 15, "carbonationType": "Keg (Force)", "hideBatchEvents": true, "batchYeastsLocal": [], "carbonationForce": 21.1, "batchFermentables": [], "primingSugarEquiv": null, "measuredEfficiency": 75.43, "measuredAttenuation": 76.6, "brewControllerEnabled": false, "estimatedTotalGravity": 1.044, "fermentationStartDate": 1713045600000, "batchFermentablesLocal": [{"_id": "new-CjQmqc9Gb2UfrnZvkingD3HYZMSEmG", "use": "Boil", "name": "Barley & Rye", "type": "Liquid Extract", "color": 2, "amount": 3, "origin": "Suffolk", "supplier": "St.Peters Brewery", "inventory": 0, "potential": null, "percentage": 100