"concentration": null, "waterAdjustment": true}, {"_id": "default-1f88df", "use": "Mash", "name": "Gypsum (CaSO4)", "time": null, "type": "Water Agent", "unit": "g", "amount": 0.5, "timeIsDays": false, "waterAdjustment": true}], "notes": "This incredible Hazy IPA taste sensational, and coming in under 0.5% abv it''s a great Non-alcoholic beer that will compete with the best!\n\nHazy, Piney, Citrus, smooth and full bodied.\n\nNo-Chill/Hot Cubed.\n- Coarsely mill the grains to reduce efficiency. \n- High temperature mash BIAB 80°C for 30 Minutes, - NO SPARGE, squeeze bag.\n\n- pH is important, be sure to acidify the wort to at least a pH of 4.6 before pitching the yeast. You will only observe a drop of around 0.3-0.5 pH with such a low attenuation, so this is necessary for both overall flavour, and food safe pH (below 4.6 is safe against most pathogens).\n\n\nResults may vary.\n\nFor more information on brewing No-Low alcohol beers, visit www.ultralowbrewing.com", "style": {"_id": "default-custom-1", "name": "Non-Alcoholic Beer", "type": "Pale Lager", "fgMax": 1.035, "fgMin": 0.998, "ogMax": 1.04, "ogMin": 1.004, "abvMax": "0.5", "abvMin": "0.0", "ibuMax": "50", "ibuMin": "1", "rbrMax": 1.09, "rbrMin": 0.02, "buGuMax": 2.27, "buGuMin": 0.05, "category": "Non-Alcoholic", "colorMax": 25.380711, "colorMin": 0.507614, "styleGuide": "Non-Alcoholic <0.5%", "lovibondMax": 25.4, "lovibondMin": 0.5, "styleLetter": "A", "categoryNumber": "01", "carbonationStyle": "01A"}, "thumb": "data:image/jpeg;base64,", "water": {"mash": {"ph": 7.55, "_id": "BxaoyPTyb36ynD8b5nF6Ck46Np0eVQ", "_rev": "InRUKRIp0fKyO10c3L0qRsYSSU41Rq", "name": "Glattfelden", "type": "source", "anions": 2.684, "hidden": false, "sodium": 13.8, "calcium": 99.846, "cations": 7.208, "sulfate": 45.324, "_created": {"_seconds": 1711395249, "_nanoseconds": 482000000}, "_version": "2.10.8", "chloride": 36.72, "hardness": 330, "magnesium": 19.75, "soClRatio": 1.23, "_timestamp": {"_seconds": 1711398528, "_nanoseconds": 96