.5, "use": "Boil", "name": "East Kent Goldings (EKG)", "time": 60, "type": "Pellet", "alpha": 4.7, "usage": "Both", "amount": 45, "origin": "United Kingdom", "_editFlag": true, "actualTime": null}], "mash": {"_id": "default", "name": "Guiness BYO Mash Profile", "steps": [{"name": "Mash", "type": "Temperature", "rampTime": null, "stepTemp": 65, "stepTime": 90, "displayStepTemp": 65}, {"name": "Mashout", "type": "Temperature", "rampTime": null, "stepTemp": 74, "stepTime": 10, "displayStepTemp": 74}]}, "name": "Guiness Clone", "path": "/", "tags": null, "type": "All Grain", "_init": true, "_type": "recipe", "color": 36.9, "miscs": [{"_id": "default-2302b0", "use": "Mash", "name": "Baking Soda (NaHCO3)", "time": null, "type": "Water Agent", "unit": "g", "amount": 5, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-3b1827", "use": "Mash", "name": "Calcium Chloride (CaCl2)", "time": null, "type": "Water Agent", "unit": "g", "amount": 0.8, "timeIsDays": false, "concentration": null, "waterAdjustment": true}, {"_id": "default-1f88df", "use": "Mash", "name": "Gypsum (CaSO4)", "time": null, "type": "Water Agent", "unit": "g", "amount": 0.4, "timeIsDays": false, "waterAdjustment": true}, {"_id": "default-8mv12", "use": "Boil", "name": "Whirlfloc", "time": 15, "type": "Fining", "unit": "items", "amount": 1, "timeIsDays": false}, {"use": "Boil", "name": "CaCO3", "time": 0, "type": "Other", "unit": "g", "amount": 4}], "notes": "BRAUTAG – Dublin Velvet (Enhanced Guinness Draught)\nZielmenge: 23 L • STW: 1.041–1.042 • IBU: 34 • ABV: ~4.3 %\nMaischwasser: 22 L • Nachguss: 6–7 L • Kochvolumen: 28 L\n\nZutaten:\n2,85 kg Pale Ale Malz (Maris Otter)\n0,90 kg Gerstenflocken\n0,45 kg Röstgerste\n45 g East Kent Goldings – 60 min\nWyeast 1084 Irish Ale\n\nWasseraufbereitung für 30 L:\n0,8 g CaCl2·2H2O\n0,4 g CaSO4·2H2O\n4,0 g CaCO3\n5,0 g NaHCO3\nCaCO3 und NaHCO3 in die Maische\nCaCl2 und CaSO4 ins Brauwasser\n\nHefestarter:\n130 g Trockenmalzextrakt + 1 L Wasser 10–15 min kochen\nAuf 18–20 °C kühlen\nHefe zugeben und 12–24 h führen\nStarter vollständig mit in den Fermenter geben\n\nMaischen:\n22 L Maischwasser auf Einmaischtemperatur bringen\nEinmaischen bei 66 °C für 60 min\nAbmaischen bei 76 °C für 10 min\n\nLäutern:\n6–7 L Nachguss\nKesselvolumen nach Läutern: 28–29 L\nPreboil Gravity ~1.037\n\nKochen (60 Minuten):\n60 min: 45 g East Kent Goldings\n(optional) 10 min vor Ende: Whirlflock\nWhirlpool 10 Minuten\nZiel Stammwürze: 1.041–1.042\n\nKühlen & Transfer:\nWürze auf 18–19 °C kühlen\nIn Brewtools F40 pumpen\nStarter komplett zugeben\n\nGärung:\nHauptgärung: 18 °C für 5 Tage\nDiacetylrast: 20 °C für 48 Stunden\nCold Crash: 2–3 Tage bei 2 °C\nErwartete FG: 1.009–1.010\nABV: ~4.3–4.4 %\n\nAbfüllen ins Keg:\nKarbonisierung bei 10 °C: 0,7 bar für 48–72 h\nZiel: 1,2 Vol CO2\nServing: 0,7 bar bei 10 °C\n\nLagerung:\n7–10 Tage\nOptimal nach 2–3 Wochen\n\nVerkostung:\nCremiger als Guinness, samtiger Antrunk\nWeiches Mundgefühl, leichte Malzsüße\nRöstiger Kaffee- und Kakaoeindruck\nLeicht trockener Abgang, 34 IBU, sehr smooth", "style": {"_id": "default-47", "name": "Irish Stout", "type": "Stout", "fgMax": 1.011, "fgMin": 1.007, "ogMax": 1.044, "ogMin": 1.036, "abvMax": 4.5, "abvMin": 4, "ibuMax": 45, "ibuMin": 25, "rbrMax": 1.12, "rbrMin": 0.62, "buGuMax": 1.12, "buGuMin": 0.62, "carbMax": null, "carbMin": null, "category": "Irish Beer", "colorMax": 40, "colorMin": 25, "styleGuide": "BJCP 2015", "lovibondMax": 40, "lovibondMin": 25, "styleLetter": "B", "categoryNumber": "15", "carbonationStyle": "15B"}, "thumb": "data:image/jpeg;base64,", "water": {"mash": {"ph": 7.55, "_id": "BxaoyPTyb36ynD8b5nF6Ck46Np0eVQ", "_rev": "oRmnre0GUhZtLdfpvix0GA997BPQgO", "name": "Glattfelden", "type": "source", "anions": 8.104, "hidden": false, "sodium": 63.104, "calcium": 147.551, "cations": 13.091, "sulfate": 156.748, "_created": {"_seconds": 1711395249, "_nanoseconds": 482000000}, "_version": "2.20.3", "chloride": 105.434, "hardness": 517, "magnesium": 36.