	('07116b85-a82b-416c-92e9-96078dea47a6', 'self_hosted_profile', 'YgubJSM5wUMqdQtkkQ8Xp9Ww9dPb8X', 'Plum Porter', NULL, 3.94, 32.6, 2.6, '{"fg": 1.01, "og": 1.040452683, "_ev": 2, "_id": "YgubJSM5wUMqdQtkkQ8Xp9Ww9dPb8X", "abv": 3.94, "ibu": 32.6, "_rev": "WYAnLOgiwMmAZmHY1n7AZnvOla6sbz", "data": {"hopsAmount": 50, "mashVolume": null, "strikeTemp": null, "topUpWater": 0, "hltWaterAmount": 21.38, "mashWaterAmount": 3.5, "mashFermentables": [], "totalWaterAmount": 24.88, "allDiastaticPower": true, "mashVolumeSurplus": 0, "otherFermentables": [{"_id": "new-pqSJnkdQbsDjyf8j3jFLMgY76NTBbY", "use": "", "name": "Festival pride of London", "type": "Liquid Extract", "color": 2, "amount": 3, "origin": "", "supplier": "", "potential": null, "percentage": 100, "attenuation": null, "grainCategory": null, "potentialPercentage": null}], "spargeWaterAmount": 21.38, "mashFermentablesAmount": 0, "batchSpargeWaterAmount1": null, "batchSpargeWaterAmount2": null, "batchSpargeWaterAmount3": null, "batchSpargeWaterAmount4": null, "otherFermentablesAmount": 3}, "hops": [{"_id": "new-RvjO79Lmr4BCRhJu3F0LWsiCjYajvQ", "ibu": 32.6, "use": "Boil", "name": "Hopfenbeigabe nach 5 Tagen", "time": 60, "type": "Pellet", "alpha": 5, "amount": 50, "origin": "Im Kit beigelegen", "actualTime": null}], "mash": {"_id": "default", "name": "High fermentability", "steps": [{"name": "", "type": "Temperature", "stepTemp": 65, "stepTime": 60}]}, "name": "Plum Porter", "path": "/", "tags": null, "type": "Extract", "_init": true, "_type": "recipe", "color": 2.6, "miscs": [{"_id": "new-hlDU90AskAP9nuVwwaBIycdlEYtYji", "use": "Boil", "name": "Dextrose Bewing Sugar Pack", "time": 0, "type": "Other", "unit": "g", "amount": 1000}], "notes": "Das Bier wird nach dem Karbonisieren bei 4 Grad mit Nitro gereift.\n\n🍺 Plum🍺 Porter🍺 –🍺 Nitro🍺 Edition\nStil: London Porter mit Pflaumenfinish\nMenge: 20 L + 1 L Pflaumensaft\nABV: ~5,0–5,2 %\nDauer: ~7 Wochen (Starter → erster Antrunk)\n🍺 Zeitplan\n•\n•\n•\n•\n•\n•\n•\nStarter & Brautag: 2 Tage\nHauptgärung: 7–8 Tage\nPflaumengärung: 5–7 Tage\nDiacetylrast: 2 Tage\nCold Crash: 2–3 Tage\nKarbonisierung + Nitro: 1–2 Wochen\nReife: ab Woche 7 trinkreif\n🍺 Zutatenliste\nBasis\n•\n•\nFestival Pride of London Porter Kit\n1 L 100% Pflaumensaft (Direktsaft, ohne Zuckerzusatz)\nHefe\n•\nWyeast 1084 Irish Ale\nStarter\n•\n•\n130 g LME (aus Kit)\n1 L Wasser\nWasseraufbereitung🍺 (25🍺 L🍺 Brauwasser)\n•\n•\n•\n•\n•\nCaCl₂·2H₂O: 2 g\nCaSO₄·2H₂O (Gips): 3 g\nMgSO₄·7H₂O (Bittersalz): 0,5 g\nNaHCO₃ (Natron): 1 g\nCaCO₃ (Kreide): 0,5 g\n🍺 Starter🍺 (Tag🍺 -1)\n•\n130 g LME + 1 L Wasser 10–15 min kochen.\n•\n•\n•\nAuf 18–20 °C kühlen, mit Wyeast 1084 anstellen.\n12–24 h führen.\nAm Brautag komplett in Würze geben.\n🍺 Brautag🍺 (Tag🍺 0)\n•\n•\n•\n•\nWürze nach Kit ansetzen, 60 min kochen.\nAuf 18–20 °C kühlen.\nStarter und Würze zusammen in Gärfass (20 L Zielvolumen).\nKräftig belüften, bei 18 °C anstellen.\n🍺 Gärplan\n•\n•\n•\n•\nHauptgärung🍺 (Tag🍺 0–7/8): 18–20 °C\nPflaumenzugabe🍺 (Tag🍺 7–8):\n◦\n◦\n◦\n1 L Pflaumensaft 10 min bei 75 °C pasteurisieren\nAuf 20 °C kühlen, vorsichtig zugeben\nWeitere 5–7 Tage bei 18–20 °C\nDiacetylrast🍺 (Tag🍺 13–15): 21 °C, 2 Tage\nEndkontrolle: SG 2 Tage stabil\n❄🍺 Cold🍺 Crash\n•\nTag 15–18: 2–3 °C, 2–3 Tage\n🍺 Karbonisierung🍺 &🍺 Nitro\n•\n•\nVorkarbonisierung🍺 (Tag🍺 18–19):\n◦\nCO₂ bei 0,6 bar / 4 °C für 48 h (~1,2 Vol. CO₂)\nNitro-Reifung🍺 (Tag🍺 21–28):\n◦\n70:30 N₂/CO₂, Druck 1,4–1,6 bar, Temp. 2–4 °C\n◦\n1–2 Wochen reifen lassen\n🍺 Ausschank\n•\n•\n•\nTrinkreif: ab Woche 7\nAusschank bei 5–7 °C\nZapfen über Stout-Nitro-Tap bei 1,7–1,9 bar\n🍺 Verkostungsnotizen\n•\nAroma: röstig, Schokolade, Kaffee, Karamell, dezent Pflaume\n•\n•\n•\nAntrunk: cremig, mittelkräftig, malzig-röstig\nAbgang: trocken, samtig, klarer Pflaumennachklang\nMundgefühl: cremig-dicht, Nitro-Schaum, niedrige Kohlensäure\n🍺 Keg-Label🍺 (letzte🍺 Seite)\nPlum🍺 Porter🍺 –🍺 Nitro🍺 Edition\n•\n•\n•\n•\n•\n•\n•\n•\n•\nStil: London Porter mit Pflaumenfinish\nABV: ~5,0–5