	('4f16a1a5-ce6b-4332-b56d-68c2f5687bb4', 'self_hosted_profile', 'gYcDzWgRMtNkOWuoZbE1lPNqI0A0Vg', 'Märzen "Kellerklar"', 'Märzen', 0, 0, NULL, '{"fg": null, "og": null, "_ev": 2, "_id": "gYcDzWgRMtNkOWuoZbE1lPNqI0A0Vg", "abv": 0, "ibu": 0, "img": "users/UGOVrmU16ieMftasdOX7ECNZNFO2/images/recipes/gYcDzWgRMtNkOWuoZbE1lPNqI0A0Vg/gYcDzWgRMtNkOWuoZbE1lPNqI0A0Vg.png", "_rev": "8Ul0cLntKS2WG1xP8TdyLkfej1Nbsj", "data": {"hopsAmount": 63, "mashVolume": 22.242, "strikeTemp": null, "topUpWater": 0, "hltWaterAmount": 14.34, "mashWaterAmount": 17.82, "mashFermentables": [{"_id": "new-HTNRmVZpFo9MnpLVR0zu9exQmQLGGZ", "name": "Wiener Malz", "type": "Grain", "unit": "kg", "amount": 4.78, "percentage": 72.42, "addAfterBoil": false, "grainCategory": "Base"}, {"_id": "new-QChJrPw5Qnaj19S1UDjWU8wydY0myz", "name": "Pilsner Malz", "type": "Grain", "unit": "kg", "amount": 1.25, "percentage": 18.94, "addAfterBoil": false, "grainCategory": "Base (Pilsner)"}, {"_id": "new-7x45j9RBJQvOIRILZQBh52jpa9dW40", "name": "Münchner Malz Typ 1", "type": "Grain", "unit": "kg", "amount": 0.4, "percentage": 6.06, "addAfterBoil": false, "grainCategory": "Base"}, {"_id": "new-8jMDtG4i5hym4UNHIxz40xFs7Inc58", "name": "CaraHell", "type": "Grain", "unit": "kg", "amount": 0.17, "percentage": 2.58, "addAfterBoil": false, "grainCategory": "Crystal/Caramel"}], "totalWaterAmount": 32.16, "allDiastaticPower": false, "mashVolumeSurplus": 0, "otherFermentables": [], "spargeWaterAmount": 14.34, "totalDiastaticPower": 0, "mashFermentablesAmount": 6.6, "batchSpargeWaterAmount1": null, "batchSpargeWaterAmount2": null, "batchSpargeWaterAmount3": null, "batchSpargeWaterAmount4": null, "otherFermentablesAmount": 0}, "hops": [{"_id": "new-A8wKDm8mK3IXi94Ks0O3PdnauA0hEB", "ibu": 0, "use": "Boil", "name": "Hallertauer Mittelfrüh", "time": 60, "type": "Pellet", "unit": "g", "alpha": 3.7, "amount": 48, "actualTime": null}, {"_id": "new-A8wKDm8mK3IXi94Ks0O3PdnauA0hEB", "ibu": 0, "use": "Boil", "name": "Hallertauer Mittelfrüh", "time": 10, "type": "Pellet", "unit": "g", "alpha": 3.7, "amount": 15, "actualTime": null}], "mash": {"name": "Vollmaisch - trockenes Märzen", "steps": [{"name": "Einmaischen", "type": "infusion", "stepTemp": 62, "stepTime": 45}, {"name": "Maltoserast", "type": "infusion", "stepTemp": 67, "stepTime": 25}, {"name": "Verzuckerung", "type": "infusion", "stepTemp": 72, "stepTime": 15}, {"name": "Abmaischen", "type": "infusion", "stepTemp": 78, "stepTime": 10}]}, "name": "Märzen \"Kellerklar\"", "path": "/", "tags": null, "type": "All Grain", "_init": true, "_type": "recipe", "color": null, "miscs": [{"_id": "default-07adb1", "use": "Sparge", "name": "Lactic Acid", "time": null, "type": "Water Agent", "unit": "ml", "amount": 0.23, "timeIsDays": false, "concentration": 88, "waterAdjustment": true}], "notes": "Trocken & sauber, mittelkräftig. Ziel: 25 L in den Fermenter für 22 L Ausschank (17 L Keg + 5x1 L Flaschen). Hopfen: Hallertauer Mittelfrüh 3.7% AA. Münchner Malz Typ 1.\n\n🍺 MÄRZEN „KELLERKLAR“\n\nStil: Märzen (untergärig, klassisch bayerisch)\nCharakter: trocken, sehr sauber, mittelkräftig\nBrauer: Alexander Studer\n\nSetup:\n- Sudhaus: Brewtools B40\n- Fermenter: Brewtools F40\n- Abfüllung: 17 L Keg + 5 × 1 L Flaschen\n- Lagerung: Keller ~14 °C\n\n────────────────────────────────────\nMAXIMALE GESAMTDAUER (Starter → Antrunk)\n7–9 Wochen\n────────────────────────────────────\n\nZIELWERTE\n- Sudgröße Fermenter: 25,0 L\n- Ausschankmenge: 22,0 L\n- Stammwürze (STW): 1.054 SG\n- Restextrakt (REx): ~1.012 SG\n- Alkohol: ~5,6 % vol\n- Bittere: ~22 IBU\n- Farbe: ~11 EBC\n\n────────────────────────────────────\nZUTATENLISTE\n────────────────────────────────────\n\nMALZ (Vollmaisch – 6,60 kg)\n- 4,78 kg Wiener Malz\n- 1,25 kg Pilsner Malz\n- 0,40 kg Münchner Malz Typ 1\n- 0,17 kg CaraHell\n\nHOPFEN\n- Hallertauer Mittelfrüh, 3,7 % α\n  - 48 g – 60 min\n  - 15 g – 10 min\n\nHEFE\n- SafLager W-34/70 – 2 Päckchen (3 optional bei sehr kaltem Anstellen)\n\n────────────────────────────────────\nHEFESTARTER (PFLICHT)\n────────────────────────────────────\n- 130 g Originalmalz aus der Schüttung (fein geschrotet)\n- 1,0 L Wasser\n- 10–15 Minuten kochen\n- Auf 18–20 °C abkühlen\n- Hefe zugeben\n- 12–24 Stunden führen\n- Am Brautag KOMPLETT inkl. Flüssigkeit in die Hauptwürze geben\n\n────────────────────────────────────\nWASSERAUFBEREITUNG\n────────────────────────────────────\nZielprofil: Munich / German Lager – Balanced\n\nZugaben auf Gesamtwasser (~32–33 L):\n- 3,5 g Calciumchlorid-Dihydrat (CaCl₂·2H₂O)\n- 4,5 g Calciumsulfat-Dihydrat (CaSO₄·2H₂O)\n\nKeine Carbonate nötig.\n\n────────────────────────────────────\nMAISCHPLAN (Vollmaisch)\n────────────────────────────────────\n1) Einmaischen:   62 °C – 45 min\n2) Maltoserast:  67 °C – 25 min\n3) Verzuckerung: 72 °C – 15 min\n4) Abmaischen:   78 °C – 10 min\n\n────────────────────────────────────\nKOCHPLAN\n────────────────────────────────────\n- Kochzeit: 75 Minuten\n- Hopfengaben wie oben\n- Ziel: klare, stabile Würze\n\n────────────────────────────────────\nGÄRPLAN (untergärig)\n────────────────────────────────────\n\nHauptgärung:\n- Anstellen bei 9 °C\n- 9–10 °C für 6–8 Tage\n- Ziel SG vor Rast: ~1.020\n\nDiacetylrast (immer):\n- 15 °C für 48 Stunden\n- Ziel: ≤ 1.014 SG\n\nCold Crash:\n- 2 °C für 3–4 Tage\n\n────────────────────────────────────\nABFÜLLUNG & KARBONISIERUNG\n────────────────────────────────────\n\nKEG (17 L):\n- Abfüllung bei 2–4 °C\n- Ziel: 2,4 Vol. CO₂\n- ca. 1,0 bar bei 4 °C für 7 Tage\n- Schnellmethode optional\n\nFLASCHEN (5 × 1 L):\n- Ziel: 2,4 Vol. CO₂\n- Zucker: 5,5 g pro Liter\n- Gesamt: 27–28 g Zucker\n- Zucker in wenig Wasser aufkochen, abkühlen, gleichmäßig verteilen\n- Nachgärung: 10–14 Tage bei 18–20 °C\n- Danach kühl lagern\n\n────────────────────────────────────\nLAGERUNG & REIFE\n────────────────────────────────────\n- Trinkreif: ab Woche 6\n- Optimal: 8–10 Wochen\n\n────────────────────────────────────\nVERKOSTUNGSNOTIZEN\n────────────────────────────────────\nAroma: Brotkruste, dezente Honignote, sehr sauber\nAntrunk: weich, mittelkräftig, sofort trocken\nAbgang: klar, crisp, animierend\nMundgefühl: rund, nicht süß, sehr süffig\n\n────────────────────────────────────\nKEG-LABEL (KOMPAKT)\n────────────────────────────────────\nName: Märzen „Kellerklar“\nStil: Märzen\nABV: ~5,6 %\nSTW: 1.054 SG\nREx: ~1.012 SG\nIBU: ~22\nEBC: ~11\nMenge: 22 L\nBrautag: __________\nAbfüllung: __________\nErster Antrunk ab: 6–8 Wochen\nHauptzutaten: Wiener Malz, Hallertauer Mittelfrüh, W-34/70\nKarbonisierung: CO₂ (optional Nitro)\nLagerhinweis: kühl & dunkel lagern", "style": {"name": "Märzen", "notes": "Clean, malt-forward, dry finish, moderate bitterness.", "rbrMax": 1.36, "rbrMin": 0.07, "buGuMax": 1.35, "buGuMin": 0.07, "category": "Lager", "styleGuide": "Classic", "lovibondMax": null, "lovibondMin": null}, "thumb": "data:image/jpeg;base64,", "water": {"mash": {"ph": 7.55, "_id": "BxaoyPTyb36ynD8b5nF6Ck46Np0eVQ", "_rev": "vL2NHCOeMYO3CA6aI2W97DbhSJPKSZ", "name": "Glattfelden", "type": "source", "anions": 1.557, "hidden": false, "sodium": 13.8, "calcium": 85.8, "cations": 6.507, "sulfate": 27.95, "_created": {"_seconds": 1711395249, "_nanoseconds": 482000000}, "_version": "2.20.3", "chloride": 24.7, "hardness": 295, "magnesium": 19.75, "soClRatio": 1.13, "_timestamp": {"_seconds": 1764333027, "_nanoseconds": 175000000}, "alkalinity": 13.9309, "ionBalance": 31, "bicarbonate": 17, "_timestamp_ms": 1764333027175, "ionBalanceOff": true, "bicarbonateMeqL": 0.2786154451291465, "residualAlkalinity": -58.96706, "residualAlkalinityMeqLCalc": -1.54076}, "meta": {"equalSourceTotal": true}, "style": "default-4", "total": {"ph": 7.55, "_id": "BxaoyPTyb36ynD8b5nF6Ck46Np0eVQ", "_rev": "vL2NHCOeMYO3CA6aI2W97DbhSJPKSZ", "name": "Glattfelden", "type": "source", "anions": 1.557, "hidden": false, "sodium": 13.8, "calcium": 85.8, "cations": 6.507, "sulfate": 27.95, "_created": {"_seconds": 1711395249, "_nanoseconds": 482000000}, "_version": "2.20.3", "chlo