tes": ""}], "mash": {"_id": "default-pr-baar", "name": "Protein rest plus beta- and alpha- amylase rests", "steps": [{"name": "Protein", "type": "Temperature", "rampTime": null, "stepTemp": 50, "stepTime": 45, "displayStepTemp": 50}, {"name": "Saccharification 1", "type": "Temperature", "rampTime": null, "stepTemp": 64, "stepTime": 60, "displayStepTemp": "64"}, {"name": "Saccharification 2", "type": "Temperature", "rampTime": null, "stepTemp": 72, "stepTime": 20, "displayStepTemp": "72"}, {"name": "Mash Out", "type": "Temperature", "rampTime": null, "stepTemp": 77, "stepTime": 15, "displayStepTemp": "77"}]}, "name": "Tripel Karmeliet - Clone", "path": "", "tags": null, "type": "All Grain", "_type": "recipe", "color": 4.6, "miscs": [{"_id": "default-pfj81e2", "use": "Boil", "_rev": "j3nvA94nmmuwAXAEgKQbniS3NzUHWV", "name": "Protafloc", "time": 15, "type": "Fining", "unit": "ml", "notes": "", "amount": 1.214, "_created": {"_seconds": 1564572563, "_nanoseconds": 74000000}, "_version": "1.9.0", "inventory": 15, "userNotes": "", "_timestamp": {"_seconds": 1564572903, "_nanoseconds": 258000000}, "amountPerL": 0.05, "timeIsDays": false, "substitutes": "", "_timestamp_ms": 1564572903258, "costPerAmount": null}, {"_id": "XvzZRMduuxxXrsCdxloo9DSYtUCINk", "use": "Boil", "_rev": "hSkbyDNkXZDEr9Bz2XpZwnn8ijh2mF", "name": "Yeast Nutrients", "time": 15, "type": "Other", "unit": "g", "notes": "", "amount": 2.223, "_parent": "default-yn1j28sf", "_created": {"_seconds": 1543671200, "_nanoseconds": 332000000}, "_version": "1.3.1", "userNotes": "", "_timestamp": {"_seconds": 1543671200, "_nanoseconds": 332000000}, "amountPerL": null, "timeIsDays": false, "substitutes": ""}], "notes": "I added a small amount of Pale Ale malt to get everything green in the style template for Belgian Tripel. If you don''t want that just \ndelete and add the same amount of Pilsner Malt instead. I tried to stick to all Belgian malts but ofcourse you can change that \nas well.\n\nDough-in protease rest at 50C for 45 minutes. Saccharification-1 temp to 64C for 60 minutes. Saccharification-2 temp\nto 72C for 20 minutes. Mash out at 77C for 15 minutes. 90 minute boil. Add Blanc Soft Sugar at boil hot break. Chill to\n18C. Pitch yeast. Pure O2 via 0.5 micron diffusion for 60 seconds. Ramp primary up to 24C over 6 days. At 1.013 dump\nprimary yeast and chill to 10C for 4 weeks. At 1.012 bottle prime in heavy bottles with Simplicity Candi Syrup at\n34g/3,79 lit and a fresh re-pitch 400ml starter. Hold bottles at 22C for 2 weeks for initial carbonation. Cellar for 3 months.\n\n\n", "style": {"_id": "default-90", "name": "Belgian Tripel", "type": "Strong Ale", "fgMax": 1.014, "fgMin": 1.008, "ogMax": 1.085, "ogMin": 1.075, "abvMax": 9.5, "abvMin": 7.5, "ibuMax": 40, "ibuMin": 20, "rbrMax": 0.54, "rbrMin": 0.27, "buGuMax": 0.5, "buGuMin": 0.25, "carbMax": null, "carbMin": null, "category": "Trappist Ale", "colorMax": 7, "colorMin": 4.5, "styleGuide": "BJCP 2015", "lovibondMax": 7, "lovibondMin": 4.5, "styleLetter": "C", "categoryNumber": "26", "carbonationStyle": "26C"}, "thumb": "data:image/jpeg;base64,", "water": {"mash": {"ph": 8, "_id": "default", "name": "Default", "type": "source", "anions": 1.153, "sodium": 6, "calcium": 18, "cations": 1.159, "sulfate": 8, "chloride": 10, "hardness": 45, "magnesium": 0, "soClRatio": 0.8, "alkalinity": 35.2369, "ionBalance": 0, "bicarbonate": 43, "ionBalanceOff": false, "bicarbonateMeqL": 0.7047331847384293, "residualAlkalinity": 22.3795, "residualAlkalinityMeqLCalc": 0.38393}, "total": {"ph": 8, "_id": "default", "name": "Default", "type": "source", "anions": 1.153, "sodium": 6, "calcium": 18, "cations": 1.159, "sulfate": 8, "chloride": 10, "hardness": 45, "magnesium": 0, "soClRatio": 0.8, "alkalinity": 35.2369, "ionBalance": 0, "bicarbonate": 43, "ionBalanceOff": false, "bicarbonateMeqL": 0.7047331847384293, "residualAlkalinity": 22.3795, "residualAlkalinityMeqLCalc": 0.38393}, "mashPh": 5.81, "source": {"ph": 8, "_id": "default", "name