INSERT INTO "aibrewgenius"."how_to_topics" ("id", "user_profile_id", "title", "content", "pages", "position", "created_at", "updated_at") VALUES
	('424b9e99-d7d6-419e-9df0-9502714b62ad', 'self_hosted_profile', 'Hefe Starter und Anwendung', '', '[{"id": "dccf3dc3-70e1-4f52-bd59-8ef61a923b9c", "title": "Hefe Starter Rezept und Anwendung ", "content": "\nKompaktanleitung – 2× 0,5-L-Gläser → Starter + Dekantieren\n\n\n\nStarterwürze auf Vorrat (pro Glas)\n\n\t• 400 ml Wasser\n\t• 40 g DME extra hell\n\t• 0,15–0,18 g Hefenährsalz\n\t• Glas handfest schließen\n\nSterilisation: Dampfkochtopf 121 °C / 15 min\nLagerung: geschlossen, dunkel, haltbar (Monate–Jahre)\n\n\n\nStarter ansetzen (Anwendung)\n\n\t1. 2 Gläser öffnen, in Erlenmeyer kippen (≈ 800 ml).\n\t2. Hefe zugeben (Bankhefe vorher auftauen, Glycerin kurz abgießen).\n\t3. Rühren bei 18–20 °C für 36–48 h.\n\n\n\nDekantieren\n\n\t4. 12 h bei ~7 °C kaltstellen.\n\t5. 90–95 % Überstand abgießen.\n\n\n\nPitching\n\n\t6. Hefeschlamm auf Anstelltemperatur bringen.\n\t7. Pitchen (Würze gut belüften).\n\n\nMerke:\n\n\t• 2 Gläser = echter Starter (untere sichere Grenze).\n\t• Nährsalz nicht überdosieren.\n\t• Dekantieren Pflicht für null Geschmackseintrag.\n"}, {"id": "a6cc6592-7fb9-4b2f-8b5a-295ef4adfa02", "title": "Erfahrung", "content": "Am 09.01.2025 habe ich den neune Hefestartet mit eine aktivierten Hefe gestartet. Innerhalb einer Stunde fing das an zu schäumen und die Hefe war innerhalb von 3 h auf dem Höhepunkt der Vergährung. Den MAgnetstabrührer konnte ich zum erstenmla überhaupt auf max Leistung drehen lassen."}]', 0, '2026-01-10 10:13:02.260122+00', '2026-01-10 10:13:02.260122+00'),
	('136029e5-125e-41cc-8bda-f0a09132f40b', 'self_hosted_profile', 'Neues Themtesta', '', '[{"id": "33633002-d911-4d70-b05a-35a411076f28", "title": "Seite 1test", "content": ""}, {"id": "5677bbde-0835-444c-a772-6e0440ce8c8e", "title": "Neue Seite 2", "content": ""}]', 1, '2026-01-10 10:19:28.928692+00', '2026-01-10 10:25:02.171741+00'),
	('1b8d8780-0a46-44d7-9ed3-b001d67bd0df', 'self_hosted_profile', 'Cryopreservative', '', '[{"id": "ce9b4bca-59fa-4c10-972a-d5c8faf3b25b", "title": "Rezept", "content": "25ml Glycerin (32 Gramm)\n75 ml Wasser\n\nIn einem sauberen (StarSan) Mehrzweckglas mischen .Handfest anziehen und im Dampfkochtopf für 15 min sterilisieren lassen.\nÜber Nacht langsam abkühlen lassen , damit ein unterdruck im Glas entsteht.\n\nDanach Hefe mit den 100 ml Cryo in ein sauberes Plastikgefäss geben.\nZuerst in Propanol langsam im Gefrierer einfrieren . Nach ca2 Tagen aus dem propanol nehmen und normal bis zur nächsten Anwendung Einfrieren."}, {"id": "1688c8f5-57a4-442d-8d71-9f897ab4858b", "title": "YouTube Anleitung", "content": "https://www.youtube.com/watch?v=uxnUrDIqN5g&t=299s"}]', 2, '2026-01-10 10:25:39.208409+00', '2026-01-10 10:29:24.958943+00'),
	('f47ac10b-58b2-4d72-8f92-7f28b3e94a8d', 'self_hosted_profile', 'pH-Wert optimieren', '', '[{"id": "b1e2e3e4-f5f6-4a7b-8c9d-123456789001", "title": "Bedeutung", "content": "Der pH-Wert beeinflusst die Enzymaktivität (Amylasen) und Extraktion. Ein zu hoher pH-Wert (>6,0) beim Läutern löst unerwünschte Gerbstoffe aus den Spelzen."}, {"id": "b1e2e3e4-f5f6-4a7b-8c9d-123456789002", "title": "Der perfekte Zeitpunkt", "content": "Messung ca. 10-15 Min nach dem Einmaischen. Probe unbedingt auf Zimmertemperatur abkühlen (wichtig für die Messgenauigkeit!). Zielbereich: 5,2 - 5,5 pH."}, {"id": "b1e2e3e4-f5f6-4a7b-8c9d-123456789003", "title": "Korrektur", "content": "Zu hoch? Milchsäure oder Sauermalz schrittweise zugeben und nach 5 Min erneut messen. Zu niedrig? (Selten) Mit Backpulver (Natron) oder kalkhaltigem Leitungswasser gegensteuern."}, {"id": "b1e2e3e4-f5f6-4a7b-8c9d-123456789004", "title": "Nachguss", "content": "Auch das Nachgusswasser (Sparge Water) sollte auf ca. 5,5 - 5,8 pH eingestellt werden, um die Auslaugung von Spelzenbitterstoffen gegen Ende des Läuterns zu verhindern."}]', 3, '2026-01-12 19:38:35.528504+00', '2026-01-12 19:38:35.528504+00');


